<?php declare(strict_types=1);
namespace App\Services;
use App\Constants\StreamStatus; use App\Repositories\{ChannelRepository,PlaylistRepository,StreamRepository};
final class StreamService { public function __construct(private StreamRepository $streams,private ChannelRepository $channels,private PlaylistRepository $playlists,private LogService $log){} public function active():?array{return $this->streams->active();} public function latest():?array{return $this->streams->latest();} public function start(int $channelId,int $playlistId,?string $start,?string $end):int { if($this->streams->active())throw new \LogicException('Another stream is already active.');if(!$this->channels->find($channelId))throw new \InvalidArgumentException('Channel not found.');if(!$this->playlists->find($playlistId)||!$this->playlists->videos($playlistId))throw new \InvalidArgumentException('Playlist must contain at least one video.');if($end&&$start&&strtotime($end)<=strtotime($start))throw new \InvalidArgumentException('End time must be after start time.');$id=$this->streams->create($channelId,$playlistId,$start?:null,$end?:null);$this->log->info('Stream queued',['stream_id'=>$id]);return $id;} public function stop(int $id):void{$stream=$this->streams->find($id);if(!$stream)throw new \InvalidArgumentException('Stream not found.');$this->streams->update($id,['stop_requested'=>1]);$this->log->info('Stop requested',['stream_id'=>$id]);} public function restart(int $id):void{$stream=$this->streams->find($id);if(!$stream)throw new \InvalidArgumentException('Stream not found.');$this->streams->update($id,['restart_requested'=>1]);$this->log->info('Restart requested',['stream_id'=>$id]);} }
